import{_ as a,o as e,c as n,a2 as i}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"SD 卡烧录实战 - 先把一张卡写明白","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/flash/08_sd_card_flashing.md","filePath":"tutorial/flash/08_sd_card_flashing.md","lastUpdated":1780988513000}'),p={name:"tutorial/flash/08_sd_card_flashing.md"};function l(t,s,d,r,o,c){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="sd-卡烧录实战-先把一张卡写明白" tabindex="-1">SD 卡烧录实战 - 先把一张卡写明白 <a class="header-anchor" href="#sd-卡烧录实战-先把一张卡写明白" aria-label="Permalink to &quot;SD 卡烧录实战 - 先把一张卡写明白&quot;">​</a></h1><h2 id="前言-sd-卡流程为什么要单独讲" tabindex="-1">前言：SD 卡流程为什么要单独讲 <a class="header-anchor" href="#前言-sd-卡流程为什么要单独讲" aria-label="Permalink to &quot;前言：SD 卡流程为什么要单独讲&quot;">​</a></h2><p>前面几章我们已经把完整镜像做出来了。现在问题变成另一个很实际的事情：怎么把这个 <code>.img</code> 写进一张真正的 SD 卡，然后让板子从它启动。</p><p>这一步看起来简单，命令也就一条 <code>dd</code>。但说实话，很多烧录事故都不是脚本写错，而是写错了主机设备。比如把 <code>/dev/sdX1</code> 当成整盘写，或者把主机硬盘误认成 SD 卡。<code>dd</code> 不会问你“真的要覆盖吗”，它会很认真地把你给它的目标抹掉。</p><p>所以这一章不会上来就让你敲命令。我们先确认镜像，再确认设备，最后再写卡。</p><h2 id="先生成-sd-镜像" tabindex="-1">先生成 SD 镜像 <a class="header-anchor" href="#先生成-sd-镜像" aria-label="Permalink to &quot;先生成 SD 镜像&quot;">​</a></h2><p>从项目根目录执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/release-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --boot-media</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果前面的 release 产物都已经在 <code>out/release-latest/</code> 里，也可以直接调用镜像脚本：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/image_builder/build_imx6ull_image.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --release-dir=out/release-latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --boot-media=sd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>生成结果应该在这里：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/images/imx6ull-aes-sd.img</span></span>
<span class="line"><span>out/release-latest/images/imx6ull-aes-sd.img.manifest</span></span>
<span class="line"><span>out/release-latest/images/imx6ull-aes-sd.img.sha256</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这里一定要注意文件名里的 <code>sd</code>。当前项目约定是：</p><table tabindex="0"><thead><tr><th>介质</th><th>U-Boot 设备</th><th>Linux root</th></tr></thead><tbody><tr><td>SD</td><td><code>mmc 0</code></td><td><code>/dev/mmcblk0p2</code></td></tr><tr><td>eMMC</td><td><code>mmc 1</code></td><td><code>/dev/mmcblk1p2</code></td></tr></tbody></table><p>SD 镜像里面的启动参数就是按这个约定生成的。拿 eMMC 镜像去烧 SD 卡，有时候也能看到 U-Boot，有时候甚至能加载到内核，但内核挂 rootfs 的时候很容易掉进 <code>VFS: Cannot open root device</code>。</p><div class="tip custom-block"><p class="custom-block-title">v1.0.0 验证基线</p><p>SD 卡镜像 <code>imx6ull-aes-sd.img</code> 已由仓库主作者 CharlieChen114514 在正点原子阿尔法 i.MX6ULL 开发板上实验启动通过。本章后续排查默认以 <code>mmc 0</code> 和 <code>root=/dev/mmcblk0p2</code> 为基线。</p></div><h2 id="烧录前先看-manifest" tabindex="-1">烧录前先看 manifest <a class="header-anchor" href="#烧录前先看-manifest" aria-label="Permalink to &quot;烧录前先看 manifest&quot;">​</a></h2><p>先别急着插卡。先确认这个镜像确实是 SD 版本：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,80p&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes-sd.img.manifest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>重点看这几行：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>boot_media=sd</span></span>
<span class="line"><span>uboot_mmc_dev=0</span></span>
<span class="line"><span>linux_root_dev=/dev/mmcblk0p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>再看一下分区表：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sfdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes-sd.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>正常情况下，第一个分区从 16 MiB 开始：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...img1 : start=32768, size=131072, type=83, bootable</span></span>
<span class="line"><span>...img2 : start=163840, size=..., type=83</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这些检查都不会修改镜像。把这一步养成习惯，后面排查能省很多时间。</p><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h2><p>孩子们我偷懒了直接，Rufus是一个好用的工具，直接选择镜像咱们构建的镜像烧录进去就完事了。关键点只有一个：选择 DD/raw image 模式，把整个 <code>.img</code> 写进整张 SD 卡。</p><p>Linux的用户看下边</p><h2 id="linux-wsl用户-找到主机上的-sd-卡设备" tabindex="-1">Linux/WSL用户 找到主机上的 SD 卡设备 <a class="header-anchor" href="#linux-wsl用户-找到主机上的-sd-卡设备" aria-label="Permalink to &quot;Linux/WSL用户 找到主机上的 SD 卡设备&quot;">​</a></h2><p>插入 SD 卡之前，先看一次块设备：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>插入 SD 卡，再看一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>新增出来的那个整盘设备，就是目标设备。它可能长这样：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sdb      8:16   1  29.7G  0 disk</span></span>
<span class="line"><span>├─sdb1   8:17   1    64M  0 part</span></span>
<span class="line"><span>└─sdb2   8:18   1   512M  0 part</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>（我反复强调下，你的不一定是sdb哈，看你多出来了哪一个！）。这时整盘路径是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/sdb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/sdb1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>写完整 raw image 必须写整盘。因为镜像里本来就包含 MBR、raw U-Boot 区域、boot 分区和 rootfs 分区。你写到分区上，相当于把整盘结构塞进了一个分区内部，板子当然很难启动。</p><p>如果桌面环境自动挂载了 SD 卡分区，先卸载：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdb1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdb2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这里的 <code>/dev/sdb</code> 只是例子。实际操作一定换成你机器上 <code>lsblk</code> 看到的新增设备。</p><h2 id="用-dd-写入" tabindex="-1">用 dd 写入 <a class="header-anchor" href="#用-dd-写入" aria-label="Permalink to &quot;用 dd 写入&quot;">​</a></h2><p>确认目标是整盘设备后，执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=out/release-latest/images/imx6ull-aes-sd.img</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  of=/dev/sdX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  bs=4M</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  status=progress</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  conv=fsync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>写完再同步一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>conv=fsync</code> 会让 <code>dd</code> 在结束前尽量把数据刷到设备上。后面的 <code>sync</code> 是再稳一手，尤其是用 USB 读卡器时，不要看到命令返回就马上拔卡。你知道的，硬盘操作远慢于内存读写，有时候操作系统小小的缓存机制可能会坑人。。。</p><h2 id="上板启动" tabindex="-1">上板启动 <a class="header-anchor" href="#上板启动" aria-label="Permalink to &quot;上板启动&quot;">​</a></h2><p>把 SD 卡插到板子上，启动模式拨到 SD。上电后进入 U-Boot，可以先做几条手动检查：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc list</span></span>
<span class="line"><span>mmc dev 0</span></span>
<span class="line"><span>mmc part</span></span>
<span class="line"><span>ext4ls mmc 0:1 /</span></span>
<span class="line"><span>ext4ls mmc 0:2 /</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><code>mmc dev 0</code> 能选中 SD，<code>ext4ls mmc 0:1 /</code> 能看到 <code>zImage</code> 和 <code>imx6ull-aes.dtb</code>，说明 boot 分区至少是能读的。</p><p>如果当前 U-Boot 环境里有 <code>sdbootaes</code>，直接跑：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>run sdbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果环境里没有，可以快速设置一套：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># SD 快速启动环境设置</span></span>
<span class="line"><span>setenv sd_dev 0</span></span>
<span class="line"><span>setenv fdt_addr 0x83000000</span></span>
<span class="line"><span>setenv sdargs &#39;setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk0p2 rootwait rw&#39;</span></span>
<span class="line"><span>setenv loadsdimage &#39;ext4load mmc \${sd_dev}:1 \${loadaddr} /zImage&#39;</span></span>
<span class="line"><span>setenv loadsdfdt &#39;ext4load mmc \${sd_dev}:1 \${fdt_addr} /imx6ull-aes.dtb&#39;</span></span>
<span class="line"><span>setenv sdbootaes &#39;echo Booting AES from SD ...; run sdargs; mmc dev \${sd_dev}; run loadsdimage; run loadsdfdt; bootz \${loadaddr} - \${fdt_addr}&#39;</span></span>
<span class="line"><span>saveenv</span></span>
<span class="line"><span>run sdbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>手动启动兜底（不依赖预设环境变量）：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk0p2 rootwait rw</span></span>
<span class="line"><span>ext4load mmc 0:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>ext4load mmc 0:1 \${fdt_addr} /imx6ull-aes.dtb</span></span>
<span class="line"><span>bootz \${loadaddr} - \${fdt_addr}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这里最关键的是两个 <code>0</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc 0:1</span></span>
<span class="line"><span>root=/dev/mmcblk0p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>前者是 U-Boot 从 SD 的第一个分区加载内核和 DTB，后者是 Linux 挂 SD 的第二个分区作为根文件系统。</p><h2 id="linux-起来后看什么" tabindex="-1">Linux 起来后看什么 <a class="header-anchor" href="#linux-起来后看什么" aria-label="Permalink to &quot;Linux 起来后看什么&quot;">​</a></h2><p>系统启动后，先看内核实际拿到的参数：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/cmdline</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>再看根目录挂载在哪：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39; / &#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果系统里有 <code>lsblk</code>，也可以看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>SD 启动时，根分区应该是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/dev/mmcblk0p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你看到 <code>/dev/mmcblk1p2</code>，那就说明启动参数还是 eMMC 口径。回去检查镜像 manifest，或者检查 U-Boot 环境变量是不是覆盖了镜像里的默认命令。</p><h2 id="常见现象" tabindex="-1">常见现象 <a class="header-anchor" href="#常见现象" aria-label="Permalink to &quot;常见现象&quot;">​</a></h2><h3 id="写卡后主机还能看到旧分区" tabindex="-1">写卡后主机还能看到旧分区 <a class="header-anchor" href="#写卡后主机还能看到旧分区" aria-label="Permalink to &quot;写卡后主机还能看到旧分区&quot;">​</a></h3><p>这种情况常见于写完后桌面缓存没刷新，或者你写错了设备。</p><p>先拔插 SD 卡，再看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果分区大小、卷标、数量完全没变，优先怀疑 <code>of=</code> 写错了。正确目标应该是整盘设备，例如 <code>/dev/sdb</code>，不是 <code>/dev/sdb1</code>。</p><h3 id="u-boot-里-ext4ls-失败" tabindex="-1">U-Boot 里 ext4ls 失败 <a class="header-anchor" href="#u-boot-里-ext4ls-失败" aria-label="Permalink to &quot;U-Boot 里 ext4ls 失败&quot;">​</a></h3><p>先确认选的是 SD：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc dev 0</span></span>
<span class="line"><span>mmc part</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果 <code>mmc part</code> 看不到两个分区，说明卡里整盘布局可能没写进去。回主机用：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sfdisk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdX</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>确认真实 SD 卡上是否有从 <code>32768</code> 扇区开始的第一个分区。</p><h3 id="内核提示-vfs-无法打开-root" tabindex="-1">内核提示 VFS 无法打开 root <a class="header-anchor" href="#内核提示-vfs-无法打开-root" aria-label="Permalink to &quot;内核提示 VFS 无法打开 root&quot;">​</a></h3><p>这个问题通常不是 <code>zImage</code> 坏了，而是 root 参数和真实设备对不上。SD 流程应该是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root=/dev/mmcblk0p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果串口里看到的是 <code>/dev/mmcblk1p2</code>，那就是把 eMMC 启动参数带过来了。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>SD 卡流程适合第一次验证镜像，也适合快速换卡测试。下一章我们看 eMMC：它不能直接插到主机上，所以要先用 UUU 把 U-Boot 跑进 RAM，再让 U-Boot 把 eMMC 暴露成 UMS。</p><p><strong>下一步：</strong> 阅读 <a href="./09_uuu_ums_emmc_flashing">09_uuu_ums_emmc_flashing.md</a>。</p>`,92)])])}const u=a(p,[["render",l]]);export{b as __pageData,u as default};
